const I18N_LANGS = [
  { code: 'tr', name: 'Türkçe',   flag: '🇹🇷' },
  { code: 'en', name: 'English',  flag: '🇬🇧' },
  { code: 'de', name: 'Deutsch',  flag: '🇩🇪' },
  { code: 'ru', name: 'Русский',  flag: '🇷🇺' },
  { code: 'zh', name: '中文',      flag: '🇨🇳' },
];

// Dil seçimi:
//  1) Kullanıcı daha önce dili açıkça seçtiyse (localStorage.lang) onu kullan.
//  2) Aksi halde tarayıcının/sistemin dil tercihlerini (navigator.languages)
//     destekleneninlere göre dene.
//  3) Hiçbiri uymazsa İngilizce'ye düş — daha önce 'tr' fallback'i, sistem
//     dili İngilizce/Almanca/vs. olan kullanıcıları Türkçe'ye zorluyordu.
let _lang = null;
try { _lang = localStorage.getItem('lang'); } catch(e){}
if (!_lang) {
  const _candidates = []
    .concat(navigator.language || [])
    .concat(navigator.languages || []);
  for (const c of _candidates) {
    const code = String(c || '').toLowerCase().split('-')[0];
    if (I18N[code]) { _lang = code; break; }
  }
}
if (!_lang || !I18N[_lang]) _lang = 'en';

function t(key, params) {
  const dict = I18N[_lang] || I18N.en;
  // Eksik anahtarlar için İngilizce'ye düş; o da yoksa anahtarı olduğu gibi
  // dön (geliştirici görsün, kullanıcı kötü bir UX yaşamasın).
  let s = dict[key] != null ? dict[key] : (I18N.en[key] != null ? I18N.en[key] : key);
  if (params) {
    for (const k in params) {
      s = s.split('{' + k + '}').join(params[k]);
    }
  }
  return s;
}

function getLang() { return _lang; }

function setLanguage(lang) {
  if (!I18N[lang]) return;
  _lang = lang;
  try { localStorage.setItem('lang', lang); } catch(e){}
  document.documentElement.lang = lang;
  applyLanguage();
}

function applyLanguage() {
  // Update [data-i18n] -> textContent
  document.querySelectorAll('[data-i18n]').forEach(el => {
    el.textContent = t(el.dataset.i18n);
  });
  // [data-i18n-html] -> innerHTML
  document.querySelectorAll('[data-i18n-html]').forEach(el => {
    el.innerHTML = t(el.dataset.i18nHtml);
  });
  // [data-i18n-ph] -> placeholder
  document.querySelectorAll('[data-i18n-ph]').forEach(el => {
    el.placeholder = t(el.dataset.i18nPh);
  });
  // [data-i18n-title] -> title
  document.querySelectorAll('[data-i18n-title]').forEach(el => {
    el.title = t(el.dataset.i18nTitle);
  });
  // [data-i18n-help] -> data-help (drives CSS tooltip)
  document.querySelectorAll('[data-i18n-help]').forEach(el => {
    el.setAttribute('data-help', t(el.dataset.i18nHelp));
  });
  document.documentElement.lang = _lang;
  // Re-render dynamic content (functions defined in app.js)
  if (typeof renderSidebar === 'function') { try { renderSidebar(); } catch(e){} }
  if (typeof renderWatches === 'function') { try { renderWatches(); } catch(e){} }
  if (typeof renderNotificationLog === 'function') { try { renderNotificationLog(); } catch(e){} }
  if (typeof renderWatchBanner === 'function') { try { renderWatchBanner(); } catch(e){} }
  if (typeof updateBulkFileBtn === 'function') { try { updateBulkFileBtn(); } catch(e){} }
  if (typeof updateBulkLinkBtn === 'function') { try { updateBulkLinkBtn(); } catch(e){} }
  if (typeof renderDownloadsTab === 'function') { try { renderDownloadsTab(); } catch(e){} }
  if (typeof applySyncStatusToUI === 'function') { try { applySyncStatusToUI(); } catch(e){} }
  if (typeof updateLastSyncDisplay === 'function') { try { updateLastSyncDisplay(); } catch(e){} }
  if (typeof loadFiles === 'function' && typeof S !== 'undefined' && S.activeTab === 'files') { try { loadFiles(); } catch(e){} }
  if (typeof loadLinks === 'function' && typeof S !== 'undefined' && S.activeTab === 'links') { try { loadLinks(); } catch(e){} }
  if (typeof loadStatus === 'function' && typeof S !== 'undefined' && S.activeTab === 'status') { try { loadStatus(); } catch(e){} }
  if (typeof fetchStats === 'function') { try { fetchStats(); } catch(e){} }
  // Active state on language cards
  document.querySelectorAll('.lang-card').forEach(c =>
    c.classList.toggle('active', c.dataset.lang === _lang)
  );
}

window.addEventListener('DOMContentLoaded', () => {
  // Apply on initial load; ayrıca <html lang="..."> attribute'unu da
  // ekran okuyucular/SEO için algılanan dile çek.
  document.documentElement.lang = _lang;
  applyLanguage();
});
